mapper.select:
SELECT ft.type_name AS typeName, COUNT(ro.id) AS count FROM repair_order ro JOIN fault_type ft ON ro.fault_type_id = ft.id WHERE ro.status NOT IN (5, 6)
AND DATE(ro.create_time) >= #{startDate}
AND DATE(ro.create_time) <= #{endDate}
GROUP BY ro.fault_type_id, ft.type_name ORDER BY count DESC

SELECT r.id AS repairmanId, u.real_name AS repairmanName, COUNT(ro.id) AS completedOrders, ROUND(AVG(oe.score), 2) AS avgScore FROM order_process op JOIN repairman r ON op.repairman_id = r.id JOIN user u ON r.user_id = u.id JOIN repair_order ro ON op.order_id = ro.id AND ro.status = 4 LEFT JOIN order_evaluation oe ON ro.id = oe.order_id
AND DATE(ro.create_time) >= #{startDate}
AND DATE(ro.create_time) <= #{endDate}
GROUP BY r.id, u.real_name ORDER BY completedOrders DESC, avgScore DESC
LIMIT #{limit}
